INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2277, 203215, 5, 1288, 'just waiting', '不记得她和他是怎么认识的,只是知道他们读在同一间市重点小学,然后他们同路,于是一起坐公交,再然后一起骑自行车,打打闹闹,开开玩笑,不知不觉中就这样过去了六年.
<br>毕业了，奇迹般地,他们又读在了同一间重点中学,整整又是六年他们又是同学,也许真的是一种幸福的延续,他们仍旧跟以前一样,一起上学,她比他早一站上车,可是他们却约好了坐同一班公交车,于是他一上车变会把书包推给坐在作为上的她,他们一起放学,一起回家,有时肚子饿了，他们还会一起去吃沙茶面,他每次都吃的很快，慢慢地看着她把那碗面吃完,然后付了钱两个人满足地离开.偶尔他们还会去逛街买磁带买片子看，他喜欢刘德华,她喜欢郑伊健,他常说郑伊健是长毛怪,气得她老是追着他打.有一阵子,他骑车上学，放学时,他总会载着她回家,骑着车子在缘当湖旁的市府大道上狂飙,风吹着头发飘的飘的.那时候的感情真的就是那么的简单.仅仅是因为顺路而变得很真很真很好很好.当时他们有彼此喜欢的人,她帮他追他喜欢的女生,他追了那女生好久,她帮他买了好几次生日礼物,永远都是水晶音乐盒,最终他仍旧没有跟那女生一起,她替他感到可惜.时间在不经意间就这样过去了，高考来临了,紧张的学习仍旧没有影响他们各自的生活习惯还是一样地上学一起,读书一个班,放学又一起做伴.上课时他们一前一后坐得很近,然后无聊的课上他们会轻轻地哼着歌,日子总是这么逍遥自在,谁也不知道将来会有什么变化.只是珍惜着过着每天的紧张日子.
<br>突然有一天，他告诉她,他要出国了，然后开始,她疯狂地到处逛只为了能买到一本可以做为同学路的本子,最后她终于找到了，然后他成了那本留言簿上第一个留言的人,他在留言本上很亲切地叫上了他给她赋予的最特别的称呼&quot;花花&quot;，那个称呼是他给她的，因此也成为了她如今最幸福甜蜜的称呼.留言写的很简单，很简单，只是单纯的祝福,没有太多的感慨与怀念，甚至只是非常平常的一句话&quot;祝你考上理想的大学&quot;,也许这是那时候任何人在留言本上所写下的最真实最真挚的祝福了.他也不例外.也许那时候他们谁也没有想到过那年之后会有这么多的事情发生，这么多的变化发生.
<br>高考前,他离开了去了NZ, 之后生活似乎也就恢复了以前的样子,只是剩下了她自己一个上学放学的,最后她干脆也住到姑姑假了，因为比较近,也许那时真的只是为了近,或许是因为他已经没有陪她了.
<br>一天放学，他的好朋友跑来告诉她, 他来信了，于是那人把信给她看了，她哭了, 因为他在那里生活的不如意而哭泣,他的信里只是把在那里生活简单地说了，可是不明白为什么她哭了，而且一提到就掉眼泪,她当时也不知道为什么,只是后来才明白过来，也许这就是一种喜欢一种爱吧,也许是这么多年下来的一种依恋吧!只是这种感情是不知不觉中滋长出来的吧!
<br>终于，高考结束了，她没有考上好的大学，只是读了一间不怎么起眼的普通高校,十二年的重点换回来一间无所谓的学校,她觉得很难过,于是她开始上网给他发了邮件，倾诉了许多复杂的东西，之后他们开始定下时间聊天,渐渐地,他们之间的距离因为网络而贴近了，终于有一天,她告诉他,她们班打算跟一个男生比较多的班级联谊,他告诉她别去了，小心别的男生不好,她临下线的那一刹那, 他说了一句话,好好照顾自己哦， 别忘了&quot;你是我的女人&quot;,就是那一句话，令她的心里起了阵涟漪.之后的聊天仍是不紧不慢地进行着,终于他要回来了，兴奋又激动中,他回来了.
<br>那年,她大学的第一年，他回来了，给她打了电话,让她猜猜他在哪里?她竟然在电话那头听到了熟悉厦门话，她知道他回来了，心突然跳得厉害,整整一年没有见了，她把头发给留起来了，因为他喜欢长头发的女孩,她开了门,见到了站在门口的他,似乎他一点都没有改变，唯一变化的是,她心里对他的那份感觉.他看她的眼神似乎也多了另外一些东西.
<br>后来她常想如果没有当初的分离,也许他们根本不可以会有故事......
<br>那一年,对她来说是幸福的开始,也许也是一个痛苦的开始吧~~就在那年，他牵起了她的手,发誓要爱她一生一世.她永远都记得,那天他们在拥挤的人群里穿梭着,他突然转过头告诉她人多别跟丢了，于是一把抓起了她的手,她把头低了下来,他还笑着说她脸红得不成样了.那时候的情感真的就是那么的简单,简单地喜欢简单地爱.....那一年，她跟他一起过了圣诞节,她的生日,那年的生日，她收到了他送给她的一个戒指,她至今仍套在受伤,还有春节...之后他走了又会到NZ 去了，去之前他告诉她,让她一定等他,他会给她电话的,还有信...
<br>他走了,2001年2月13日,似乎真的很残忍的，他离开的日子选在了情人节的前夕,在有情人的日子里,她过着一个没有情人的情人节...他托好朋友给她带来了一盒巧克力,在麦当劳里,那人把巧克力给她时,她哭了...
<br>接下来的日子里,就只有他的邮件跟电话陪伴着她,她真的很想他,很想他,于是她开始写日记了，厚厚的一本簿子,她很快就写完了，记下了所有的点点滴滴,有时她还给他写信，呵呵,她开心地悄悄地叫那些信为情书，但是她却没有给他寄出去,因为里面的心情是个秘密,偶尔他给她电话，他们会聊着彼此的生活跟境况,彼此关心着对方，有时她会忍不住哭了出来,他总是告诉她别哭了，要乖哦，听话哦,不要哭,要坚强，那时候她其实会哭得更厉害，但是都很乖巧地说恩知道了,她不想他难过...他们会聊QQ,但是5个小时的时差让她实在心疼他,他总是在半夜时跟她聊天，于是他们聊天的时间渐渐地渐渐地少了,只是通过邮件彼此联系着关心着对方,渐渐地邮件也少了，电话也少了，因为彼此都忙,但是她仍旧没有戒掉写日记的习惯,她的日记仍是厚厚地,记载着每天发生的事情,同时也有想他的心情,她不想错过每滴记忆,不想错过任何一个想他的机会,每天夜里她都会静静地想着他.....
<br>大学的生活是丰富多彩的,她算不上漂亮，但是活泼开朗,于是认识了不少好朋友,有个男生对她特别好,每天早上悄悄地在路口等着她,跟她一起上学,她起初没有在意,突然有天,好朋友告诉她,有鬼~~于是她避开了那个男生，男生终于向她表白了,她拒绝了他,告诉他她等着她爱的人呢，那人告诉她,&quot; 你努力你的,我努力我的!&quot;至今那人仍旧对她很好!但始终她都没有办法接受他...也许这就是债吧~~她仍旧坚持给他发着邮件，讲些有的没的,在学校里的事情,告诉他自己发生的一切心情故事...
<br>2002年1月21日,那天她睡得沉沉的,下午没有课快期末考了，于是她在家里休息,突然被电话给吵醒了，话筒里传来了另她兴奋不已的声音,是他,真的是他,他回来了，她开心地立刻蹦下床去,他告诉她,在她家楼下等她,她好快好快地就冲到了楼下,那一刻,她所有的细胞都为他而跳动着,那天她在日记中写到&quot;他回来了,好开心哦, :) :) :--) , 幸福的感觉真好&quot;,他送她去做家教,之后又送她回来,在她家的楼梯口他们吻别了, 那天的感觉是甜蜜的,是幸福的,虽然有点不太习惯(毕竟分开了好一年了),但是她真的觉得好幸福好幸福哦!!
<br>接下来的期末开始压得她喘不过气来,虽然很想见他，可是她却为了考试没有见他，但是他们天天都在QQ聊天,说着属于他们的甜言蜜语,1月25日,考试终于结束了，那天上网,他们聊着QQ,突然他问她,是不是有人在追她,她告诉他NO, 他突然说:&quot;他怕他会耽误她,如果她遇到更好的，他希望她不要担心, 可以告诉他.....&quot;她傻了，泪水已经布满了她的脸颊,其实她已经明白了他的意思，她只是一直告诉他,她掉线了，她多希望他能告诉她,他刚刚什么都没有说，可是他没有,他说出了那三个字&quot;分手吧&quot;...也许那时候他说分手真的是对的，至少现在她就不会这么痛苦了,也许她还找到了另外一个可以帮她忘记他的男生呢.....
<br>她整整哭了一晚上，之后的几天里表现得很平静,一样活泼开朗地说笑着,可是夜里她只是偷偷地哭泣着..日记里写着她所有的心情，她一遍一遍地看着日记， 看着他给她写的信跟邮件......那阵子,她懂得了她真的很在乎他,比自己想想中的还要在乎......
<br>她心已经沦陷了,也许没有救了，她避开他,不见他，可是他们之间那么多年的同学总是有一拖拉库的好朋友的,最后还是一起出去了，她装得若无其事的漫不经心地跟好朋友们玩着八十,可是眼角却偷偷地看着他,她知道她一点都放不下,根本不可能放得下的.
<br>那天她借口先走了，不愿意在同路一起回家了,她做不到真的做不到,她怕她会当场哭出来,真的会哭出来,她每次都会伪装得很好，其实她的心真的好痛好痛~~
<br>2月18日,他们分手24天了，她终于忍不住了，她给他打了电话,把他约了出来，她哭了，她哭着问他为什么要分手,他什么都没有说，只是简单地说不想耽误她,她说她不在乎，真的不在乎，&quot;不要分手好吗?&quot;她求了他,吻住了他,求他不要放弃她,终于她赢了，他紧紧地抱住她,她知道他不会放开她了.......2002年2月18日,他们又在一起了.....
<br>接下来的日子,他们小心翼翼地关怀着对方,他发誓,他会守着她一辈子的，她满足地编织着自己的未来....终究他仍是要会NZ的,可是他们谁都没有提起离开的日子,这年的情人节他们正在分手,于是又错过了一个情人节....
<br>2003年2月25日,他离开了厦门,又到了那个听说雪色很美的NZ了,她来到了海边看着大海,第一次什么都没有想过,只是静静地望着它,不知道自己想要些什么....她的心好空好空...好空好...空...
<br>2003年2月26日,元宵节,同学邀请她一起去看焰火,她拒绝了，自己一个人跑到大马路上乱晃,他到了香港了，给她打了电话,可是她不在家里,回来妈妈告诉她时,她急得直哭,晚上写日记的时候突然发现不知道从什么时候开始,自己已经变得很爱哭很爱哭了,日记本里有着她泪滴....
<br>之后的日子,她写着日记数着他给她打电话的日子,发邮件的日子,每天她打开电脑,拨上号,第一件事就是按下OUTLOOK 收下他的邮件，只要一看到他的油箱地址, 她就好开心好开心，好有动力好有动力,好幸福好幸福..给他写邮件就是一种幸福，她会很老实地告诉他这里发生的一切,但是她都挑好的说,不开心的,总是选择不说，或者轻描淡写地过去了,哭了伤心了，总不告诉他,她真的好怕他担心,燕说她是个傻姑娘.可是她却满不在乎,仍很幸福.......她从来都没有把感情的事想得太复杂了，也许是她总把他们之间的事想得那么简单吧....
<br>2003年11月19日,他回来了，她还记得2000年的这个日子里,是他陪着她过大学第一个运动会的,他来学校为她跑4X200接力赛加油呢,他的突然回来真的令她兴奋不已,那阵子的她天天都粘着他,他们一起逛街,逛超市,看电影,一起过圣诞一起通宵,一起做许多许多许多事,分享着好甜蜜好甜蜜的感受啊~~她告诉自己失去又得到的感觉真的好好!!她觉得他对他好好哦,连她的好朋友乔都这么说,她觉得好开心好骄傲哦，因为她觉得找到了真正对自己好的男一个可以跟她过一辈子的男人......
<br>2003年1月1日,他们一大群人庆祝新年,通宵没有回家,他在屋顶上楼着她,她好幸福哦，看着璀璨的夜色,她心里默默地告诉自己,如果时间停止那该多好,永远就这样下去,永远就这样幸福下去,真的，在朋友的眼里，他们是幸福的,至少他们彼此爱着对方，珍惜着对方,而且他们认识N久了，那么了解对方了，永远的幸福其实离他们真的不远.......其实那天过后他就又该准备收拾行囊又一次启程了,谁又能体会她的心情呢??
<br>2003年1月3日,他回到NZ了..........
<br>接下来的故事,似乎有点老调了，但是却是真实得不能在真实了......
<br>她依然给他邮件,告诉他,她找实习单位的事情;告诉他,她的论文写不完了;告诉他,她又换单位了;告诉他许多许多.......但是她唯独没有告诉他,其实她好辛苦好累,她家里发生了很大的变故,父亲的再次投资失败了，家里负债了，她必须出来工作了，学校要她继续读书,她放弃了，然后银行让她去上班,她放弃了，因为她需要一份工作，一份至少她觉得工资还不错的工作，但是她每天都要加班,每天一大早就得起床去上班,然后一直上班到晚上11点才回家，有时候一躺下就想睡,她真的好累, 有时候真想有个肩膀靠一靠....依然，她什么都没有告诉他,他什么也不知道,只是会告诉她,好好照顾自己,工作找份轻松点的,别累了...依然,她等待着他的电话，可是,他的电话少之又少,他在邮件里告诉她,他很累,他每天都要打工又要读书，没有时间给她电话,看到这时,她在心里已经不怪他了,相反的她好心疼他,却又不知道怎么去帮助他,她告诉他,该好好照顾自己,累了就休息一下，别太勉强了,有天她突然发了邮件告诉他,她觉得自己实在很不称职,至少不能帮男朋友分忧,不能帮他分担辛劳,她哭了,她认为自己不够好,不够爱他,至少没有他那么爱她....依然,她会写日记,依然天天写,依然记着点点滴滴的情感....依然她会在夜里偷偷哭泣....在梦里见到他,在梦中醒来时找不到他, 有时候半夜她醒了,找不到他时,她会好着急好着急,自己一个人躲在被窝里哭泣,搁天同学看到时,她总说昨天喝太多水了,然后一副若无其事的样子依旧活泼开朗地玩笑着,打闹着.......依然,她认为他们会有结果,会有美好的未来，会有将来属于他们的自己的幸福......依然.....
<br>2003年2月14日,情人节里,一大早，他打了电话来她家，可是她一大早就去上班了，然后他赶忙又给她打手机,结果她在电梯里,又没有收到,终于晚上了，她去参加了表哥的婚礼,她真的好羡慕他们,终于走到了一起, 她想到了他,眼圈红红的,一晚上她好沉默,然后她突然好想给他个电话，可是她却怎么样都找不到电话号码,突然发现，她从来没有给他打过电话，其实她根本就没有他的电话号码,他总是告诉她,他会给她电话的， 然后什么都没有留给她....又是一个情人节...... 一个没有他的情人节......
<br>2003年5月1日,她以为他会给她电话的，可是没有,以前每次休息的日子他都会给她电话的，可是没有，这个节日因为没有他的电话,让她觉得好悲凉.....
<br>2003年5月13日,她接到了哥哥的电话，他从外地回来了，他想见她,她如期来到了大嫂家,哥哥变胖了，她嬉笑着数落他,她告诉他,她工作的一切,哥哥告诉她,这样很好,她很聪明地避开不谈他的事,可是哥哥却问起了，其实哥哥已经不止一次这么说她了，他曾经很婉转地告诉她,别等他了,并且列举了很多很多的理由，但是她每次都一笑而过,什么都没有说...事实上,很多朋友都这么说过她,他们担心她这么傻等不会有好结果的,&quot;他会回来吗?&quot;他们问,&quot;我不知道&quot;她回答,大家无奈地看着她,她笑了笑,依然坚持着......
<br>哥哥终于忍不住了，告诉她,&quot;别傻了，他不值得你这么付出,他不配~~&quot;她迷茫地看着她哥,哥哥严肃地告诉她&quot;他不值得,那种耐不住寂寞的男人不值得你等待......&quot;她看着哥哥的脸,想从中得到点什么,哥哥残忍地说,&quot;早就该告诉过你了，有些时候男人不象你们女人.......他在NZ 与另外一个女人同居了.....&quot;接下去的话,她什么都没有听到,&quot;同居&quot;两个字深深地深深地扎进她的心里,她的脸上什么表情都没有,心一下字变得好空好空,什么感觉都没有了,她不知道自己是怎么离开大嫂家里的,只是手里写着一个号码,一个那女生的QQ号码&quot;自己如果不相信,可以去证实&quot;这是哥哥的话,她什么都没有说，来到了实习单位，她也不知道自己是怎么完成一下午的工作的，又是怎么离开办公室回家的,她只知道,她坐着车子来来回回好几趟,什么都想,仅仅是静静地坐着.....
<br>接下来的这几天,她真的不知道心里什么样的滋味，什么样的感觉~~哥哥把事情告诉了她的密友，希望L跟F能劝劝她,他们好担心哦，赶忙给她打电话,电话里,他们关心地询问着她,并且劝她算了,该放开了，&quot;他这么做根本没有考虑过你的感受!!&quot;她什么都没有说，她只是一个劲地说，&quot;为什么我的心没有什么痛的感觉呢?为什么我都不哭呢??&quot;乔知道了，她问她,&quot;你是不是还没有反映过来?&quot;
<br>其实他们的关心,她真的明白，只是....其实她已经好几个晚上没有睡了~~~~
<br>2003年5月18日,她终于忍不住，上了QQ ,加了那个女生作为好友,他们开始聊天了，她骗了那女生说她即将出国了，然后询问NZ 的生活情况,那女生跟她聊了，她告诉她,她叫AMY,于是讲到了感情问题,她突然发现这为AMY好现实哦， 因为她真的很懂得对自己好,她知道她要什么样的幸福，也许只是很短暂的，AMY 很现实地告诉她一切她的幸福，原来他已经把AMY 带回到厦门过,她突然觉得心好痛好痛,他们回来过，可是她却不知道,甚至每年他的回来都是她幸福的开始,她不知道他是怎么能这样的,她不信,她真的不信,她爱了这么多年的男人怎么可以这样...AMY 在QQ 的那端尽情地说着她的故事,她在这里手脚冰凉,厦门的天气其实不冷，可是那晚上她真的觉得好冷哦，她静静地看着那头像一闪一闪地说着些让她痛得很的话,她真的真的好冷....终于AMY 说出了他的名字，她的心突然觉得有个大口子,好大好大,不知道谁这么残忍用刀往上这么狠狠地给了一刀,她没有泪,没有感觉，断了线,躺在床上用棉被把自己裹得严严实实的,那一晚,她的脑子里不停地闪过的,是他们曾经的一幕幕,她真的不愿意相信，当年那个骑着车子载她回家的那个男生会这样欺骗她,她不愿意相信,那个曾经对她山盟海誓的男生会这样对她,&quot;我每年都跟他一起先回厦门,然后再回老家的....,厦门真的狠美.....&quot;那女生的这句话，一直在脑子里盘旋着,她真的不知道怎么了,她的心就是这么痛,这么在意这句话,他把她带回厦门了，可是我却全然不知,然后他又跟我在一起....天啊....我该恨他吗?我好想恨他啊,她这么想着，可是...她做不到,她心里想得到的全是他的好,全是他们在一起的日子,他们分开,她想他的日子.......她整整折磨了自己又是一夜.....
<br>搁天,L, F, 乔,全都给她电话了，他们骂的骂,安慰的安慰，始终不知道她的决定是什么，他们没有办法了，最后只好说，如果你真的恨难决定的话，那就选择让自己快乐的方式,毕竟我们希望你快乐，但是你真的真的要快乐....我们会永远祝福你,伴随你的.真的好庆幸,他们没有离开她,她不是一无所有的...她知道自己不能放下他，她做不到,真的做不到.......她只有继续等他，直到有一天心真的死了.......
<br>谁又能告诉她该如何呢????也许这就是欠债吧,上辈子欠他的，这辈子注定要还了的....她这么告诉自己.....
<br>周末他要给她电话了，她又开始等待着.....等待着........', '不记得她和他是怎么认识的,只是知道他们读在同一间市重点小学,然后他们同路,于是一起坐公交,再然后一起骑自行车,打打闹闹,开开玩笑,不知不觉中就这样过去了六年.

毕业了，奇迹般地,他们又读在了同一间重点中学,整整又是六年他们又是同学,也许真的是一种幸福的延续,他们仍旧跟以前一样,一起上学,她比他早一站上车,可是他们却约好了坐同一班公交车,于是他一上车变会把书包推给坐在作为上的她,他们一起放学,一起回家,有时肚子饿了，他们还会一起去吃沙茶面,他每次都吃的很快，慢慢地看着她把那碗面吃完,然后付了钱两个人满足地离开.偶尔他们还会去逛街买磁带买片子看，他喜欢刘德华,她喜欢郑伊健,他常说郑伊健是长毛怪,气得她老是追着他打.有一阵子,他骑车上学，放学时,他总会载着她回家,骑着车子在缘当湖旁的市府大道上狂飙,风吹着头发飘的飘的.那时候的感情真的就是那么的简单.仅仅是因为顺路而变得很真很真很好很好.当时他们有彼此喜欢的人,她帮他追他喜欢的女生,他追了那女生好久,她帮他买了好几次生日礼物,永远都是水晶音乐盒,最终他仍旧没有跟那女生一起,她替他感到可惜.时间在不经意间就这样过去了，高考来临了,紧张的学习仍旧没有影响他们各自的生活习惯还是一样地上学一起,读书一个班,放学又一起做伴.上课时他们一前一后坐得很近,然后无聊的课上他们会轻轻地哼着歌,日子总是这么逍遥自在,谁也不知道将来会有什么变化.只是珍惜着过着每天的紧张日子.

突然有一天，他告诉她,他要出国了，然后开始,她疯狂地到处逛只为了能买到一本可以做为同学路的本子,最后她终于找到了，然后他成了那本留言簿上第一个留言的人,他在留言本上很亲切地叫上了他给她赋予的最特别的称呼"花花"，那个称呼是他给她的，因此也成为了她如今最幸福甜蜜的称呼.留言写的很简单，很简单，只是单纯的祝福,没有太多的感慨与怀念，甚至只是非常平常的一句话"祝你考上理想的大学",也许这是那时候任何人在留言本上所写下的最真实最真挚的祝福了.他也不例外.也许那时候他们谁也没有想到过那年之后会有这么多的事情发生，这么多的变化发生.

高考前,他离开了去了NZ, 之后生活似乎也就恢复了以前的样子,只是剩下了她自己一个上学放学的,最后她干脆也住到姑姑假了，因为比较近,也许那时真的只是为了近,或许是因为他已经没有陪她了.

一天放学，他的好朋友跑来告诉她, 他来信了，于是那人把信给她看了，她哭了, 因为他在那里生活的不如意而哭泣,他的信里只是把在那里生活简单地说了，可是不明白为什么她哭了，而且一提到就掉眼泪,她当时也不知道为什么,只是后来才明白过来，也许这就是一种喜欢一种爱吧,也许是这么多年下来的一种依恋吧!只是这种感情是不知不觉中滋长出来的吧!

终于，高考结束了，她没有考上好的大学，只是读了一间不怎么起眼的普通高校,十二年的重点换回来一间无所谓的学校,她觉得很难过,于是她开始上网给他发了邮件，倾诉了许多复杂的东西，之后他们开始定下时间聊天,渐渐地,他们之间的距离因为网络而贴近了，终于有一天,她告诉他,她们班打算跟一个男生比较多的班级联谊,他告诉她别去了，小心别的男生不好,她临下线的那一刹那, 他说了一句话,好好照顾自己哦， 别忘了"你是我的女人",就是那一句话，令她的心里起了阵涟漪.之后的聊天仍是不紧不慢地进行着,终于他要回来了，兴奋又激动中,他回来了.

那年,她大学的第一年，他回来了，给她打了电话,让她猜猜他在哪里?她竟然在电话那头听到了熟悉厦门话，她知道他回来了，心突然跳得厉害,整整一年没有见了，她把头发给留起来了，因为他喜欢长头发的女孩,她开了门,见到了站在门口的他,似乎他一点都没有改变，唯一变化的是,她心里对他的那份感觉.他看她的眼神似乎也多了另外一些东西.

后来她常想如果没有当初的分离,也许他们根本不可以会有故事......

那一年,对她来说是幸福的开始,也许也是一个痛苦的开始吧~~就在那年，他牵起了她的手,发誓要爱她一生一世.她永远都记得,那天他们在拥挤的人群里穿梭着,他突然转过头告诉她人多别跟丢了，于是一把抓起了她的手,她把头低了下来,他还笑着说她脸红得不成样了.那时候的情感真的就是那么的简单,简单地喜欢简单地爱.....那一年，她跟他一起过了圣诞节,她的生日,那年的生日，她收到了他送给她的一个戒指,她至今仍套在受伤,还有春节...之后他走了又会到NZ 去了，去之前他告诉她,让她一定等他,他会给她电话的,还有信...

他走了,2001年2月13日,似乎真的很残忍的，他离开的日子选在了情人节的前夕,在有情人的日子里,她过着一个没有情人的情人节...他托好朋友给她带来了一盒巧克力,在麦当劳里,那人把巧克力给她时,她哭了...

接下来的日子里,就只有他的邮件跟电话陪伴着她,她真的很想他,很想他,于是她开始写日记了，厚厚的一本簿子,她很快就写完了，记下了所有的点点滴滴,有时她还给他写信，呵呵,她开心地悄悄地叫那些信为情书，但是她却没有给他寄出去,因为里面的心情是个秘密,偶尔他给她电话，他们会聊着彼此的生活跟境况,彼此关心着对方，有时她会忍不住哭了出来,他总是告诉她别哭了，要乖哦，听话哦,不要哭,要坚强，那时候她其实会哭得更厉害，但是都很乖巧地说恩知道了,她不想他难过...他们会聊QQ,但是5个小时的时差让她实在心疼他,他总是在半夜时跟她聊天，于是他们聊天的时间渐渐地渐渐地少了,只是通过邮件彼此联系着关心着对方,渐渐地邮件也少了，电话也少了，因为彼此都忙,但是她仍旧没有戒掉写日记的习惯,她的日记仍是厚厚地,记载着每天发生的事情,同时也有想他的心情,她不想错过每滴记忆,不想错过任何一个想他的机会,每天夜里她都会静静地想着他.....

大学的生活是丰富多彩的,她算不上漂亮，但是活泼开朗,于是认识了不少好朋友,有个男生对她特别好,每天早上悄悄地在路口等着她,跟她一起上学,她起初没有在意,突然有天,好朋友告诉她,有鬼~~于是她避开了那个男生，男生终于向她表白了,她拒绝了他,告诉他她等着她爱的人呢，那人告诉她," 你努力你的,我努力我的!"至今那人仍旧对她很好!但始终她都没有办法接受他...也许这就是债吧~~她仍旧坚持给他发着邮件，讲些有的没的,在学校里的事情,告诉他自己发生的一切心情故事...

2002年1月21日,那天她睡得沉沉的,下午没有课快期末考了，于是她在家里休息,突然被电话给吵醒了，话筒里传来了另她兴奋不已的声音,是他,真的是他,他回来了，她开心地立刻蹦下床去,他告诉她,在她家楼下等她,她好快好快地就冲到了楼下,那一刻,她所有的细胞都为他而跳动着,那天她在日记中写到"他回来了,好开心哦, :) :) :--) , 幸福的感觉真好",他送她去做家教,之后又送她回来,在她家的楼梯口他们吻别了, 那天的感觉是甜蜜的,是幸福的,虽然有点不太习惯(毕竟分开了好一年了),但是她真的觉得好幸福好幸福哦!!

接下来的期末开始压得她喘不过气来,虽然很想见他，可是她却为了考试没有见他，但是他们天天都在QQ聊天,说着属于他们的甜言蜜语,1月25日,考试终于结束了，那天上网,他们聊着QQ,突然他问她,是不是有人在追她,她告诉他NO, 他突然说:"他怕他会耽误她,如果她遇到更好的，他希望她不要担心, 可以告诉他....."她傻了，泪水已经布满了她的脸颊,其实她已经明白了他的意思，她只是一直告诉他,她掉线了，她多希望他能告诉她,他刚刚什么都没有说，可是他没有,他说出了那三个字"分手吧"...也许那时候他说分手真的是对的，至少现在她就不会这么痛苦了,也许她还找到了另外一个可以帮她忘记他的男生呢.....

